-- ============================================================
-- SANDBOX WeAreDevs v1.0.0 — compatível com LuaDumper/Lune
-- ============================================================
-- O LuaDumper já hookeia loadstring internamente em Rust.
-- Este sandbox só garante que getgenv() devolve um env
-- com loadstring acessível, sem quebrar o error handler
-- do LuaDumper.
-- ============================================================

-- Guarda referências originais antes de qualquer override
local _rawloadstring = rawget(_ENV, "loadstring") or loadstring
local _rawprint      = rawget(_ENV, "print")      or print
local _rawtype       = rawget(_ENV, "type")        or type

-- ─────────────────────────────────────────────────────────────
-- Stub de getgenv para ambientes sem executor (Lune, etc.)
-- O WeAreDevs faz:  local env = getgenv()  e depois
--                   env.loadstring(chunk)
-- Se getgenv for nil, o VM crasha antes de chegar no hook.
-- ─────────────────────────────────────────────────────────────
if not getgenv then
    getgenv = function()
        return _ENV
    end
end

-- ─────────────────────────────────────────────────────────────
-- Garante que getgenv() retorna um env com loadstring válido.
-- NÃO wrappeia pcall — deixa o LuaDumper tratar erros.
-- ─────────────────────────────────────────────────────────────
local _genv = getgenv()
if _genv and not _genv.loadstring then
    _genv.loadstring = _rawloadstring
end

-- ─────────────────────────────────────────────────────────────
-- Hook de loadstring — só loga, não interfere no retorno
-- ─────────────────────────────────────────────────────────────
local _captured_count = 0

local _original_ls = (_genv and _genv.loadstring) or _rawloadstring

local function hooked_loadstring(src, chunkname, ...)
    if _rawtype(src) == "string" and #src > 0 then
        _captured_count = _captured_count + 1
        _rawprint(string.rep("-", 60))
        _rawprint("[WAD] Payload #" .. _captured_count .. " | " .. #src .. " bytes")
        _rawprint(string.rep("-", 60))
        _rawprint(src)
        _rawprint(string.rep("-", 60))

        -- Salva em arquivo se disponível (Synapse, KRNL, etc.)
        if writefile then
            local fname = "wad_payload_" .. _captured_count .. ".lua"
            pcall(writefile, fname, src)
            _rawprint("[WAD] Salvo em: " .. fname)
        end
    end
    -- IMPORTANTE: retorna direto sem try/catch pra não engolir erros
    return _original_ls(src, chunkname, ...)
end

-- Aplica hook no ambiente global e local
_ENV.loadstring = hooked_loadstring
if _genv and _genv ~= _ENV then
    _genv.loadstring = hooked_loadstring
end

_rawprint("[WAD Sandbox v2] Pronto. Aguardando loadstring()...")

